import React, { useEffect, useRef, useState } from "react";
import "./App.css";
import * as faceapi from "face-api.js";

function App() {
  const videoRef = useRef(null);
  const [emotion, setEmotion] = useState("neutral");

  useEffect(() => {
    let interval;

    const startVideo = async () => {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      videoRef.current.srcObject = stream;
    };

    const loadModels = async () => {
      const MODEL_URL = process.env.PUBLIC_URL + "/models";

      await faceapi.nets.tinyFaceDetector.loadFromUri(MODEL_URL);
      await faceapi.nets.faceExpressionNet.loadFromUri(MODEL_URL);

      startDetection();
    };

    const startDetection = () => {
      interval = setInterval(async () => {
        if (!videoRef.current) return;

        const detections = await faceapi
          .detectAllFaces(
            videoRef.current,
            new faceapi.TinyFaceDetectorOptions()
          )
          .withFaceExpressions();

        if (detections.length > 0) {
          const expressions = detections[0].expressions;

          const max = Object.keys(expressions).reduce((a, b) =>
            expressions[a] > expressions[b] ? a : b
          );

          setEmotion(max);
        }
      }, 500);
    };

    startVideo();
    loadModels();

    return () => clearInterval(interval); // cleanup
  }, []);

  const getEmoji = (emotion) => {
    switch (emotion) {
      case "happy":
        return "😄";
      case "sad":
        return "😢";
      case "angry":
        return "😠";
      case "surprised":
        return "😲";
      case "neutral":
        return "😐";
      default:
        return "🙂";
    }
  };

  return (
    <div id="app" className="app">
      <div className="overlay"></div>

      <div className="text">
        <span role="img" aria-label={emotion}>
          {getEmoji(emotion)}
        </span>{" "}
        You look <span>{emotion}</span>!
      </div>

      <div className="mockup">
        <div id="browser" className="browser">
          <div className="browserChrome">
            <div className="browserActions"></div>
          </div>

          <video
            ref={videoRef}
            width="540"
            height="405"
            muted
            autoPlay
          ></video>
        </div>
      </div>

      <p className="note">
        You are not being recorded, it all happens in your own browser!
      </p>
    </div>
  );
}

export default App;
